const cluster = $('Load Cluster').first().json
const items   = $('Load Top Source Items').all().map(i => i.json)
const brand   = $('Load Brand Settings').first()?.json || {}

const itemSummaries = items.slice(0, 3)
  .map((item, i) => `${i+1}. ${item.title}`)
  .join('\n')

const prompt = `You are a social media content strategist for OUTRAGE, a pop culture and entertainment brand.

Trending topic: "${cluster.title}"
Keywords: ${(cluster.keywords || []).slice(0, 8).join(', ')}
Top stories:\n${itemSummaries}

Brand voice: ${brand.tone_keywords?.join(', ') || 'bold, provocative, culturally-aware'}
Avoid: ${brand.avoid_words?.join(', ') || 'nothing specific'}

Generate 5 content ideas in JSON format:
[
  {
    "type": "caption|hook|thread|meme_idea|reel_idea",
    "content": "the full content text",
    "angle": "hot_take|breakdown|comparison|reaction|explainer",
    "hook": "the opening line",
    "cta": "the call to action",
    "platform": "instagram|tiktok|twitter|all",
    "confidence": 0.0-1.0
  }
]

Return ONLY the JSON array, no other text.`

return [{ json: { prompt, cluster_id: cluster.id, org_id: cluster.org_id } }]

const raw = $input.first().json
let suggestions = []
try {
  const content = raw.message?.content || raw.choices?.[0]?.message?.content || '[]'
  suggestions = JSON.parse(content)
  if (!Array.isArray(suggestions)) suggestions = suggestions.ideas || []
} catch(e) {
  return [{ json: { error: 'Failed to parse OpenAI response: ' + e.message } }]
}

return [{
  json: {
    cluster_id: $('Build OpenAI Prompt').first().json.cluster_id,
    org_id:     $('Build OpenAI Prompt').first().json.org_id,
    run_id:     $('Webhook Trigger').first().json.body.run_id || null,
    status:     'success',
    items_processed: suggestions.length,
    suggestions: suggestions.map(s => ({
      ...s,
      ai_model: 'gpt-4o'
    }))
  }
}]
